from dataclasses import dataclass, field
from datetime import date

@dataclass
class RoleRedesignDocument:
    role_title: str
    business_unit: str
    effective_date: date
    redesign_facilitator: str
    tasks: list[TaskRecord]

    def total_hours_current(self) -> float:
        return sum(t.current_hours_per_week for t in self.tasks)

    def total_hours_post_redesign(self) -> float:
        return sum(t.post_redesign_hours_per_week for t in self.tasks)

    def total_hours_freed(self) -> float:
        return sum(t.hours_saved() for t in self.tasks)

    def reinvestment_capacity(self) -> str:
        hours = self.total_hours_freed()
        if hours < 1:
            return f"{hours*60:.0f} minutes per week freed — recommend self-serve artefact improvements, not structured reinvestment"
        return f"{hours:.1f} hours per week freed — reinvest in: [document specific higher-value tasks here]"

    def incomplete_redesigns(self) -> list[str]:
        return [
            f"{t.task_name}: {'; '.join(t.redesign_gaps())}"
            for t in self.tasks
            if not t.is_redesign_complete()
        ]

    def ai_assisted_zone_summary(self) -> list[dict]:
        return [
            {
                "task": t.task_name,
                "verification_criteria": t.verification_criteria,
                "accountability": t.accountability_owner,
            }
            for t in self.tasks if t.zone == "AI_ASSISTED"
        ]

doc_r = RoleRedesignDocument(
    role_title="Operations Analyst",
    business_unit="Finance Operations",
