    tasks=tasks,
)
print(f"Hours freed: {doc_r.total_hours_freed():.1f}/week")
print(doc_r.reinvestment_capacity())
print("Incomplete:", doc_r.incomplete_redesigns())
# Hours freed: 3.0/week
# 3.0 hours per week freed — reinvest in: [document specific higher-value tasks here]
# Incomplete: []

@dataclass
class ZoneChangeRequest:
    role_title: str
    task_name: str
    current_zone: Zone
    proposed_zone: Zone
    rationale: str
    requester: str
    date: date
    approved_by: str = ""
    approved_date: date | None = None

    def requires_safety_review(self) -> bool:
        # Any change TO AI_EXECUTABLE requires explicit safety review
        return self.proposed_zone == "AI_EXECUTABLE"

    def is_approved(self) -> bool:
        return bool(self.approved_by and self.approved_date)

    def approval_summary(self) -> str:
        status = "APPROVED" if self.is_approved() else "PENDING"
        safety = " [SAFETY REVIEW REQUIRED]" if self.requires_safety_review() else ""
        return (
            f"{status}{safety}: {self.task_name} "
            f"{self.current_zone} → {self.proposed_zone} "
            f"(Requested by {self.requester})"
        )
